class RalphError(RuntimeError):
    """Base error for user-facing loop failures."""


class CommandFailure(RalphError):
    """A subprocess command failed."""

    def __init__(
        self,
        command: list[str],
        cwd: Path,
        returncode: int,
        stdout: str,
        stderr: str,
        log_path: Path | None,
    ) -> None:
        super().__init__(f"Command failed ({returncode}): {format_command(command)}")
        self.command = command
        self.cwd = cwd
        self.returncode = returncode
        self.stdout = stdout
        self.stderr = stderr
        self.log_path = log_path


class CommandTimeout(CommandFailure):
    """A subprocess command exceeded its configured timeout."""

    def __init__(
        self,
        command: list[str],
        cwd: Path,
        timeout_seconds: int | float,
        stdout: str,
        stderr: str,
        log_path: Path | None,
    ) -> None:
        RalphError.__init__(
            self,
            f"Command timed out after {timeout_seconds:g}s: {format_command(command)}",
        )
        self.command = command
        self.cwd = cwd
        self.returncode = 124
        self.stdout = stdout
        self.stderr = stderr
        self.log_path = log_path
        self.timeout_seconds = timeout_seconds


class IssueFailure(RalphError):
    """An issue-specific failure that should not stop the whole drain."""

    def __init__(
        self,
        message: str,
        log_path: Path | None = None,
        *,
        failure_type: str | None = None,
        recovery_guidance: str | None = None,
    ) -> None:
        super().__init__(message)
        self.log_path = log_path
        self.failure_type = failure_type
        self.recovery_guidance = recovery_guidance


class FullAccessImplementationScopeFailure(IssueFailure):
    """A Full-access implementation pass changed files outside issue anchors."""


class FormatterRewriteRecoveryFailure(IssueFailure):
    """Formatter-modified files were detected, but recovery did not complete."""

    def __init__(
        self,
        *,
        reason: str,
        modified_files: list[str],
        initial_commit_log_path: Path | None,
        commit_check_log_paths: list[Path],
        retry_commit_log_path: Path | None,
    ) -> None:
        self.modified_files = list(modified_files)
        self.initial_commit_log_path = initial_commit_log_path
        self.commit_check_log_paths = list(commit_check_log_paths)
        self.retry_commit_log_path = retry_commit_log_path
        modified_lines = "\n".join(f"- {path}" for path in self.modified_files)
        commit_check_lines = "\n".join(
            f"- {log_path}" for log_path in self.commit_check_log_paths
        )
        if not commit_check_lines:
            commit_check_lines = "- <not recorded>"
        message = "\n".join(
            [
                f"Formatter-rewrite recovery failure: {reason}",
                "",
                "Formatter-modified files:",
                modified_lines,
                "",
                f"Initial commit log: {initial_commit_log_path or '<not recorded>'}",
                "Commit check logs:",
                commit_check_lines,
                f"Retry commit log: {retry_commit_log_path or '<not recorded>'}",
                "",
                f"Recovery guidance: {FORMATTER_REWRITE_RECOVERY_GUIDANCE}",
            ]
        )
        log_path = retry_commit_log_path
        if log_path is None and commit_check_log_paths:
            log_path = commit_check_log_paths[-1]
        if log_path is None:
            log_path = initial_commit_log_path
        super().__init__(
            message,
            log_path=log_path,
            failure_type=FORMATTER_REWRITE_RECOVERY_FAILURE_TYPE,
            recovery_guidance=FORMATTER_REWRITE_RECOVERY_GUIDANCE,
        )


class IssueCompletionReviewFailure(IssueFailure):
    """Automated Issue completion review found incomplete issue work."""

    def __init__(
        self,
        *,
        issue_number: int,
        findings: str,
        artifact_path: Path | None,
        log_path: Path | None,
    ) -> None:
        self.findings = findings
        self.artifact_path = artifact_path
        artifact_line = (
            f"\nReview artifact: {artifact_path}" if artifact_path is not None else ""
        )
        message = (
            f"Issue completion review failed for #{issue_number}."
            f"{artifact_line}\n\nFindings:\n\n{findings.strip() or '<none recorded>'}"
        )
        super().__init__(
            message,
            log_path=log_path,
            failure_type=ISSUE_COMPLETION_REVIEW_FAILURE_TYPE,
            recovery_guidance=(
                "Inspect the preserved implementation worktree, review artifact, "
                "and QA logs, then rerun Ralph for the issue after repairing the "
                "incomplete work."
            ),
        )


class OperatorSmokeFailure(IssueFailure):
    """A requested Operator smoke failed after Exploratory branch publication."""

    def __init__(
        self,
        *,
        issue_number: int,
        smoke_id: str,
        status: str,
        log_path: Path,
        evidence_path: Path | None,
        error: str,
        timeout: bool = False,
    ) -> None:
        failure_type = (
            OPERATOR_SMOKE_TIMEOUT_FAILURE_TYPE
            if timeout
            else OPERATOR_SMOKE_FAILURE_TYPE
        )
        guidance = (
            "Inspect the preserved Exploratory worktree, remote review branch, "
            "and Operator smoke log. Rerun the smoke from the Ralph outer loop "
            "after credentials or deployed state are repaired."
        )
        evidence_line = (
            f"\nOperator smoke evidence: `{evidence_path}`"
            if evidence_path is not None
            else ""
        )
        super().__init__(
            (
                f"Operator smoke `{smoke_id}` {status} for issue #{issue_number}: "
                f"{error}\n\nOperator smoke log: `{log_path}`{evidence_line}\n"
                f"Recovery guidance: {guidance}"
            ),
            log_path=log_path,
            failure_type=failure_type,
            recovery_guidance=guidance,
        )
        self.smoke_id = smoke_id
        self.status = status


class EnvironmentFailure(IssueFailure):
    """A local environment failure that should stop the drain."""


class QARuntimeCleanupRefusal(RalphError):
    """A QA runtime path is not safe for Ralph-owned cleanup."""


class BranchSyncFailure(EnvironmentFailure):
    """A source-to-target branch sync failure that should stop the drain."""


class IntegrationTargetBaselineFailure(EnvironmentFailure):
    """An Integration target baseline Commit check failed before issue claim."""

    def __init__(
        self,
        *,
        target_branch: str,
        command: QACommand,
        log_path: Path | None,
        reasons: tuple[str, ...],
        error: CommandFailure,
    ) -> None:
        self.target_branch = target_branch
        self.command = command
        self.reasons = reasons
        reason_text = "; ".join(reasons) if reasons else "high-risk queue state"
        guidance = integration_target_baseline_recovery_guidance(
            target_branch=target_branch,
            command=command,
            log_path=log_path,
        )
        log_line = f"\nLog: `{log_path}`" if log_path is not None else ""
        super().__init__(
            (
                "Integration target baseline health failed before claiming new "
                f"ready issue work for `origin/{target_branch}`.\n"
                f"Reason: {reason_text}\n"
                f"Failing command: `{format_command(command.args)}`\n"
                f"Test lane: `{command.name}`"
                f"{log_line}\n"
                f"Recovery guidance: {guidance}"
            ),
            log_path=log_path,
            failure_type="integration_target_baseline_failure",
            recovery_guidance=guidance,
        )
        self.command_failure = error


class PostPushFailure(RalphError):
    """A failure after main was pushed, where issue state may be inconsistent."""

    def __init__(
        self,
        message: str,
        log_path: Path | None = None,
        *,
        manifest_path: Path | None = None,
    ) -> None:
        super().__init__(message)
        self.log_path = log_path
        self.manifest_path = manifest_path


class ReadyIssueRefreshFailure(RalphError):
    """Ready issue refresh failed after implementation integration."""

    def __init__(self, message: str, log_path: Path | None = None) -> None:
        super().__init__(message)
        self.log_path = log_path


class RalphSelfUpdateRestartRequired(RalphError):
    """A Ralph loop self-update was integrated and the Operator must restart."""

    def __init__(self, *, manifest_path: Path, changed_files: list[str]) -> None:
        self.manifest_path = manifest_path
        self.changed_files = tuple(changed_files)
        super().__init__(
            "Ralph loop self-update integrated; restart the Operator before "
            "claiming more issues."
        )


def drain_fatal_stop_reason(error: Exception) -> str | None:
    if isinstance(error, ReadyIssueRefreshFailure):
        return "ready_issue_refresh_failure"
    if isinstance(error, RalphSelfUpdateRestartRequired):
        return "ralph_self_update_restart_required"
    if isinstance(error, PostPushFailure):
        return "post_push_failure"
    if isinstance(error, EnvironmentFailure):
        return "environment_failure"
    return None


